; ラドミラの塔

name = ラドミラの塔10Ｆ
insideName = 10Ｆ
upper = ラドミラの塔11Ｆ
lower = ラドミラの塔９Ｆ
level = 56
bgm = tower
margin = 3
shadow = dark
sky = dawnforest
roof = stone

; パーツ画像
━ = stone_h
✜ = stone_h
… = half
　 = marble
／ = door
∫ = pick
☖ = arch
⧻ = fence
︻ = panel
┯ = button
㊤ = ladderu
㊦ = ladderd

; 敵情報
monsters = エキドナ,セイレーン,マッドウイング,見習いサキュバス,サキュバス,エルダーサキュバス,オークキング,コボルドリーダー,サイクロプス

; 宝箱
box[1] = 金貨（超特大）,金貨（超特大）,金貨（超特大）,金貨（超特大）,金貨（超特大）
box[2] = 復活の粉,修理の巻物,修理の巻物,修理の巻物,経験のコイン（大）
box[3] = アウラの宝珠,アウラの宝珠,アウラの宝珠,アウラの宝珠,ポラリスの宝珠,ポラリスの宝珠,ポラリスの宝珠,ポラリスの宝珠

[map]
